import sys, os, re
sys.path.insert(0, '/app')
import sqlite3
from agencies_db import DATA_DIR

DB = os.path.join(DATA_DIR, "provence_callian.db")

def fix_url(u):
    u = u.strip()
    u = re.sub(r'^https?://www\.provenceimmocallian\.com/\.\./', 'https://www.provenceimmocallian.com/', u)
    u = re.sub(r'^https?://provenceimmocallian\.com/', 'https://www.provenceimmocallian.com/', u)
    if u.startswith('../'):
        u = 'https://www.provenceimmocallian.com/' + u[3:]
    return u

def photos(lst):
    return ' | '.join(fix_url(u) for u in lst if u.strip())

