def run():
    conn = sqlite3.connect(DB)
    updated = 0
    for ref, data in UPDATES.items():
        n = conn.execute(
            "UPDATE biens SET description=?, photos=? WHERE reference=?",
            (data["description"], data["photos"], ref)
        ).rowcount
        if n:
            nb_photos = len(data["photos"].split(" | ")) if data["photos"] else 0
            print(f"  [{ref}] description + {nb_photos} photos")
            updated += n
        else:
            print(f"  [!] Référence non trouvée : {ref}")
    conn.commit()
    conn.close()
    print(f"\n✓ {updated}/27 biens mis à jour")

if __name__ == "__main__":
    run()
